import type { $ZodStringFormats } from "../core/checks.js";
import type * as errors from "../core/errors.js";
import * as util from "../core/util.js";

const error: () => errors.$ZodErrorMap = () => {
  const Sizable: Record<string, { unit: string; verb: string }> = {
    string: { unit: "simvol", verb: "olmal谋d谋r" },
    file: { unit: "bayt", verb: "olmal谋d谋r" },
    array: { unit: "element", verb: "olmal谋d谋r" },
    set: { unit: "element", verb: "olmal谋d谋r" },
  };

  function getSizing(origin: string): { unit: string; verb: string } | null {
    return Sizable[origin] ?? null;
  }

  const FormatDictionary: {
    [k in $ZodStringFormats | (string & {})]?: string;
  } = {
    regex: "input",
    email: "email address",
    url: "URL",
    emoji: "emoji",
    uuid: "UUID",
    uuidv4: "UUIDv4",
    uuidv6: "UUIDv6",
    nanoid: "nanoid",
    guid: "GUID",
    cuid: "cuid",
    cuid2: "cuid2",
    ulid: "ULID",
    xid: "XID",
    ksuid: "KSUID",
    datetime: "ISO datetime",
    date: "ISO date",
    time: "ISO time",
    duration: "ISO duration",
    ipv4: "IPv4 address",
    ipv6: "IPv6 address",
    cidrv4: "IPv4 range",
    cidrv6: "IPv6 range",
    base64: "base64-encoded string",
    base64url: "base64url-encoded string",
    json_string: "JSON string",
    e164: "E.164 number",
    jwt: "JWT",
    template_literal: "input",
  };

  const TypeDictionary: {
    [k in errors.$ZodInvalidTypeExpected | (string & {})]?: string;
  } = {
    nan: "NaN",
  };

  return (issue) => {
    switch (issue.code) {
      case "invalid_type": {
        const expected = TypeDictionary[issue.expected] ?? issue.expected;
        const receivedType = util.parsedType(issue.input);
        const received = TypeDictionary[receivedType] ?? receivedType;
        if (/^[A-Z]/.test(issue.expected)) {
          return `Yanl谋艁Ed蓹y蓹r: g枚zl蓹nil蓹n instanceof ${issue.expected}, daxil olan ${received}`;
        }
        return `Yanl谋艁Ed蓹y蓹r: g枚zl蓹nil蓹n ${expected}, daxil olan ${received}`;
      }
      case "invalid_value":
        if (issue.values.length === 1) return `Yanl谋艁Ed蓹y蓹r: g枚zl蓹nil蓹n ${util.stringifyPrimitive(issue.values[0])}`;
        return `Yanl谋艁Ese莽im: a艧a臒谋dak谋lardan biri olmal谋d谋r: ${util.joinValues(issue.values, "|")}`;
      case "too_big": {
        const adj = issue.inclusive ? "<=" : "<";
        const sizing = getSizing(issue.origin);
        if (sizing)
          return `脟ox b枚y眉k: g枚zl蓹nil蓹n ${issue.origin ?? "d蓹y蓹r"} ${adj}${issue.maximum.toString()} ${sizing.unit ?? "element"}`;
        return `脟ox b枚y眉k: g枚zl蓹nil蓹n ${issue.origin ?? "d蓹y蓹r"} ${adj}${issue.maximum.toString()}`;
      }
      case "too_small": {
        const adj = issue.inclusive ? ">=" : ">";
        const sizing = getSizing(issue.origin);
        if (sizing) return `脟ox ki莽ik: g枚zl蓹nil蓹n ${issue.origin} ${adj}${issue.minimum.toString()} ${sizing.unit}`;
        return `脟ox ki莽ik: g枚zl蓹nil蓹n ${issue.origin} ${adj}${issue.minimum.toString()}`;
      }
      case "invalid_format": {
        const _issue = issue as errors.$ZodStringFormatIssues;
        if (_issue.format === "starts_with") return `Yanl谋艁Em蓹tn: "${_issue.prefix}" il蓙Eba艧lamal谋d谋r`;
        if (_issue.format === "ends_with") return `Yanl谋艁Em蓹tn: "${_issue.suffix}" il蓙Ebitm蓹lidir`;
        if (_issue.format === "includes") return `Yanl谋艁Em蓹tn: "${_issue.includes}" daxil olmal谋d谋r`;
        if (_issue.format === "regex") return `Yanl谋艁Em蓹tn: ${_issue.pattern} 艧ablonuna uy臒un olmal谋d谋r`;
        return `Yanl谋艁E${FormatDictionary[_issue.format] ?? issue.format}`;
      }
      case "not_multiple_of":
        return `Yanl谋艁E蓹d蓹d: ${issue.divisor} il蓙Eb枚l眉n蓙Ebil蓹n olmal谋d谋r`;
      case "unrecognized_keys":
        return `Tan谋nmayan a莽ar${issue.keys.length > 1 ? "lar" : ""}: ${util.joinValues(issue.keys, ", ")}`;
      case "invalid_key":
        return `${issue.origin} daxilind蓙Eyanl谋艁Ea莽ar`;
      case "invalid_union":
        return "Yanl谋艁Ed蓹y蓹r";
      case "invalid_element":
        return `${issue.origin} daxilind蓙Eyanl谋艁Ed蓹y蓹r`;
      default:
        return `Yanl谋艁Ed蓹y蓹r`;
    }
  };
};

export default function (): { localeError: errors.$ZodErrorMap } {
  return {
    localeError: error(),
  };
}
